import { useState, useEffect, useCallback, useRef } from 'react';
import type { SurahData, QuranEdition, QuranFont } from '../types';
import { db } from '../firebase';
import { normalizeArabicText } from '../utils/text';

const CORE_EDITIONS: QuranEdition[] = [
    { identifier: "quran-simple-clean", language: "ar", name: "المصحف المبسط", englishName: "Simple Clean", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" },
    { identifier: "quran-uthmani-quran-academy", language: "ar", name: "الرسم العثماني", englishName: "Uthmani (Quran Academy)", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" }
];

export const useQuranData = () => {
    const [allQuranData, setAllQuranData] = useState<{ [key: string]: SurahData[] } | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isBackgroundLoading, setIsBackgroundLoading] = useState(false);
    const [loadingEditions, setLoadingEditions] = useState<string[]>([]);
    const [error, setError] = useState<string | null>(null);
    const [availableEditions, setAvailableEditions] = useState<QuranEdition[]>(CORE_EDITIONS);

    const getEditionUrl = useCallback((edition: QuranEdition): string => {
        const { identifier, sourceApi } = edition;
        // Using api.alquran.cloud for basic text data instead of Google Storage to avoid CORS issues if not configured correctly
        if (identifier === 'quran-simple-clean') return 'https://api.alquran.cloud/v1/quran/quran-simple-clean';
        return `https://api.alquran.cloud/v1/quran/${identifier}`;
    }, []);

    const processApiData = (apiData: any): SurahData[] => {
        if (apiData.code === 200 && apiData.data && apiData.data.surahs) {
            const surahs: SurahData[] = apiData.data.surahs;

            // Bismillah cleaning logic
            const fatiha = surahs.find(s => s.number === 1);
            const definitiveBismillahText = fatiha?.ayahs[0]?.text || 'بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ';
            const normalizedBismillahFingerprint = normalizeArabicText(definitiveBismillahText).replace(/\s/g, '');
            const bismillahWordCount = definitiveBismillahText.split(' ').length;

            const cleanedSurahs = surahs.map(surah => {
                // Skip Al-Fatiha and At-Tawbah
                if (surah.number === 1 || surah.number === 9 || surah.ayahs.length === 0) {
                    return surah;
                }

                const firstAyah = surah.ayahs[0];
                if (!firstAyah.text) return surah;

                const normalizedFirstAyahFingerprint = normalizeArabicText(firstAyah.text).replace(/\s/g, '');

                if (normalizedFirstAyahFingerprint.startsWith(normalizedBismillahFingerprint)) {
                    const words = firstAyah.text.split(' ');
                    const newText = words.length > bismillahWordCount ? words.slice(bismillahWordCount).join(' ') : '';

                    const newFirstAyah = { ...firstAyah, text: newText.trim() };
                    const newAyahs = [newFirstAyah, ...surah.ayahs.slice(1)];

                    return { ...surah, ayahs: newAyahs };
                }

                return surah;
            });

            return cleanedSurahs;
        }
        throw new Error('Invalid or unexpected API data structure');
    };

    const fetchCustomEditionData = useCallback(async (editionIdentifier: string) => {
        if (allQuranData?.[editionIdentifier] || loadingEditions.includes(editionIdentifier)) {
            return;
        }

        setLoadingEditions(prev => [...prev, editionIdentifier]);
        setError(null);

        const editionToFetch = availableEditions.find(e => e.identifier === editionIdentifier);
        if (!editionToFetch) {
            console.warn(`Edition ${editionIdentifier} not found in availableEditions.`);
            setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
            return;
        }

        const url = getEditionUrl(editionToFetch);

        try {
            const response = await fetch(url);
            if (!response.ok) throw new Error(`Network response was not ok: ${response.statusText}`);
            const apiData = await response.json();
            const surahs = processApiData(apiData);
            setAllQuranData(prev => ({ ...prev, [editionIdentifier]: surahs }));
        } catch (err) {
            console.error(`Failed to fetch edition ${editionIdentifier}:`, err);
            setError(`فشل تحميل بيانات المصحف الأساسية. قد تكون هناك مشكلة في الاتصال بالإنترنت.`);
        } finally {
            setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
        }
    }, [availableEditions, getEditionUrl, allQuranData, loadingEditions]);

    const fetchCustomEditionDataRef = useRef(fetchCustomEditionData);
    useEffect(() => {
        fetchCustomEditionDataRef.current = fetchCustomEditionData;
    }, [fetchCustomEditionData]);

    useEffect(() => {
        const initializeApp = async () => {
            // Unblock UI immediately
            setIsInitialLoading(false);

            // Fetch essential data in the background
            setIsBackgroundLoading(true);
            await Promise.all([
                fetchCustomEditionDataRef.current('quran-simple-clean'),
                fetchCustomEditionDataRef.current('quran-uthmani-quran-academy')
            ]);
            setIsBackgroundLoading(false);
        };
        initializeApp();
    }, []); // Empty dependency array ensures this effect runs only once on mount.

    return {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions, error,
        dataSourceStatus: 'primary' as const, availableEditions,
        fetchCustomEditionData, getEditionUrl,
    };
};

import React from 'react';
import type { Ayah, QuranEdition, SurahData, FontSize, BrowsingMode } from '../types';

interface AyahRendererProps {
    ayahsToRender: Ayah[];
    surah: SurahData;
    highlightAyahNumber: number | null;
    onWordClick: (query: string, editionIdentifier: string, position: { surah: number; ayah: number; wordIndex: number; }) => void;
    displayEdition: QuranEdition;
    fontSize: FontSize;
    browsingMode: BrowsingMode;
    currentlyPlayingAyahGlobalNumber: number | null;
    simpleCleanData: SurahData[];
    wordPopoverState: { ayahNumberInSurah: number; simpleText: string; triggerElement: HTMLElement; } | null;
    setWordPopoverState: (state: { ayahNumberInSurah: number; simpleText: string; triggerElement: HTMLElement; } | null) => void;
    setActivePopover: (state: { ayah: Ayah; triggerElement: HTMLElement } | null) => void;
    playingAyahRef: React.RefObject<HTMLSpanElement>;
    highlightRef: React.RefObject<HTMLSpanElement>;
    firstAyahInfo: { bismillah: string; restOfAyah: string; } | null;
}

const AyahRenderer: React.FC<AyahRendererProps> = ({
    ayahsToRender, surah, highlightAyahNumber, onWordClick, displayEdition, fontSize, browsingMode,
    currentlyPlayingAyahGlobalNumber, simpleCleanData, wordPopoverState, setWordPopoverState,
    setActivePopover, playingAyahRef, highlightRef, firstAyahInfo
}) => {

    const isImlaei = displayEdition.identifier.includes('simple-clean');

    // وظيفة لتنظيف النص الإملائي من أي علامات وقف عثمانية قد تشوش البحث
    const cleanImlaiText = (text: string | undefined): string | undefined => {
        if (!text) return text;
        const marksToRemoveRegex = /[\u06D6-\u06ED]/g;
        return text.replace(marksToRemoveRegex, '');
    };

    return (
        <>
            {ayahsToRender.map((ayah, index) => {
                const isHighlighted = ayah.numberInSurah === highlightAyahNumber;
                const isPlaying = ayah.number === currentlyPlayingAyahGlobalNumber;

                const simpleSurah = simpleCleanData.find(s => s.number === surah.number);
                const simpleAyah = simpleSurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);

                const baseText = (index === 0 && firstAyahInfo) ? firstAyahInfo.restOfAyah : ayah.text;
                const textToDisplay = isImlaei ? cleanImlaiText(baseText) : baseText;

                const createUthmaniWordClickHandler = (event: React.MouseEvent<HTMLButtonElement>) => {
                    const simpleAyahText = simpleAyah?.text;
                    if (simpleAyahText) {
                        if (wordPopoverState?.ayahNumberInSurah === ayah.numberInSurah) {
                            setWordPopoverState(null);
                        } else {
                            setWordPopoverState({
                                ayahNumberInSurah: ayah.numberInSurah,
                                simpleText: simpleAyahText,
                                triggerElement: event.currentTarget,
                            });
                        }
                    }
                };

                return (
                    <span key={ayah.number} className="inline">
                        <span
                            id={`ayah-${surah.number}-${ayah.numberInSurah}`}
                            ref={isPlaying ? playingAyahRef : (isHighlighted ? highlightRef : null)}
                            className={`inline rounded-md transition-colors duration-300 ${isPlaying ? 'bg-yellow-300/40 dark:bg-yellow-400/20' : ''}`}
                        >
                            {textToDisplay?.split(' ').map((word, wordIndex, arr) => (
                                <React.Fragment key={wordIndex}>
                                    <button
                                        onClick={
                                            isImlaei
                                                ? () => onWordClick(word, displayEdition.identifier, { surah: surah.number, ayah: ayah.numberInSurah, wordIndex: wordIndex })
                                                : createUthmaniWordClickHandler
                                        }
                                        /* 
                                           ملاحظة تقنية: تم حذف أي أنماط قد تسبب "تجزئة" النص (display: inline-block)
                                           لضمان أن محرك الخط يرى الكلمة ككتلة واحدة متصلة.
                                        */
                                        className="word-trigger bg-transparent border-none p-0 font-inherit text-inherit leading-inherit cursor-pointer hover:bg-primary/10 transition-colors inline"
                                        aria-label={`خيارات الكلمة: ${word}`}
                                    >
                                        {word}
                                    </button>
                                    {wordIndex < arr.length - 1 && ' '}
                                </React.Fragment>
                            ))}
                        </span>

                        <span className="relative inline-block align-middle">
                            <button
                                onClick={(e) => setActivePopover({ ayah: ayah, triggerElement: e.currentTarget })}
                                className={`popover-trigger mx-1 select-none cursor-pointer hover:opacity-80 transition-opacity ${browsingMode === 'page' ? 'ayah-marker' : 'text-sm font-sans font-bold text-primary-text rounded-md p-1 -m-1'}`}
                                aria-label={`خيارات الآية ${ayah.numberInSurah}`}
                            >
                                {browsingMode === 'page' ? ayah.numberInSurah : `﴿${ayah.numberInSurah}﴾`}
                            </button>
                        </span>
                    </span>
                );
            })}
        </>
    );
};

export default AyahRenderer;

import React from 'react';
import type { Ayah, QuranEdition, SurahData, FontSize, BrowsingMode } from '../types';

interface AyahRendererProps {
    ayahsToRender: Ayah[];
    surah: SurahData;
    highlightAyahNumber: number | null;
    onWordClick: (query: string, editionIdentifier: string, position: { surah: number; ayah: number; wordIndex: number; }) => void;
    displayEdition: QuranEdition;
    fontSize: FontSize;
