                            onClick={handleAyahClick}
                            className={`inline transition-colors duration-300 ${isPlaying ? 'bg-yellow-300/40 dark:bg-yellow-400/20 rounded-md' : ''} ${!isImlaei ? 'cursor-pointer hover:bg-primary/5 px-1' : ''}`}
                        >
                            {isImlaei ? (
                                // في الوضع الإملائي الحروف منفصلة بطبعها فلا مشكلة من الأزرار
                                textToDisplay?.split(' ').map((word, wordIndex, arr) => (
