                                            className="bg-transparent border-none p-0 font-inherit text-inherit cursor-pointer hover:text-primary inline"
                                        >
                                            {word}
                                        </button>
                                        {wordIndex < arr.length - 1 && ' '}
                                    </React.Fragment>
                                ))
                            ) : (
                                // الحل السحري: عرض النص العثماني ككتلة واحدة صلبة لمنع تقطع الحروف
                                <span className="select-text">{textToDisplay}</span>
                            )}
                        </span>

                        <span className="relative inline-block align-middle">
                            <button
                                onClick={(e) => setActivePopover({ ayah: ayah, triggerElement: e.currentTarget })}
