export default AyahRenderer;

import { useState, useEffect, useCallback, useRef } from 'react';
import type { SurahData, QuranEdition } from '../types';
import { normalizeArabicText } from '../utils/text';

const CORE_EDITIONS: QuranEdition[] = [
    { identifier: "quran-simple-clean", language: "ar", name: "المصحف المبسط", englishName: "Simple Clean", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" },
    { identifier: "quran-uthmani-quran-academy", language: "ar", name: "الرسم العثماني", englishName: "Uthmani (Quran Academy)", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" }
];

export const useQuranData = () => {
    const [allQuranData, setAllQuranData] = useState<{ [key: string]: SurahData[] } | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isBackgroundLoading, setIsBackgroundLoading] = useState(false);
    const [loadingEditions, setLoadingEditions] = useState<string[]>([]);
    const [error, setError] = useState<string | null>(null);
    const [availableEditions] = useState<QuranEdition[]>(CORE_EDITIONS);

    const getEditionUrl = useCallback((edition: QuranEdition): string => {
        const { identifier } = edition;
        if (identifier === 'quran-simple-clean') return 'https://api.alquran.cloud/v1/quran/quran-simple-clean';
        return `https://api.alquran.cloud/v1/quran/${identifier}`;
    }, []);

    const processApiData = (apiData: any): SurahData[] => {
        if (apiData.code === 200 && apiData.data && apiData.data.surahs) {
            const surahs: SurahData[] = apiData.data.surahs;
            const fatiha = surahs.find(s => s.number === 1);
            const definitiveBismillahText = fatiha?.ayahs[0]?.text || 'بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ';
            const normalizedBismillahFingerprint = normalizeArabicText(definitiveBismillahText).replace(/\s/g, '');
            const bismillahWordCount = definitiveBismillahText.split(' ').length;

            return surahs.map(surah => {
                if (surah.number === 1 || surah.number === 9 || surah.ayahs.length === 0) return surah;
                const firstAyah = surah.ayahs[0];
                if (!firstAyah.text) return surah;
                const normalizedFirstAyahFingerprint = normalizeArabicText(firstAyah.text).replace(/\s/g, '');
                if (normalizedFirstAyahFingerprint.startsWith(normalizedBismillahFingerprint)) {
                    const words = firstAyah.text.split(' ');
                    const newText = words.length > bismillahWordCount ? words.slice(bismillahWordCount).join(' ') : '';
                    const newAyahs = [{ ...firstAyah, text: newText.trim() }, ...surah.ayahs.slice(1)];
                    return { ...surah, ayahs: newAyahs };
                }
                return surah;
            });
        }
        throw new Error('Invalid data structure');
    };

    const fetchCustomEditionData = useCallback(async (editionIdentifier: string) => {
        if (allQuranData?.[editionIdentifier] || loadingEditions.includes(editionIdentifier)) return;
        setLoadingEditions(prev => [...prev, editionIdentifier]);

        const editionToFetch = availableEditions.find(e => e.identifier === editionIdentifier);
        if (!editionToFetch) {
            setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
            return;
        }

        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 10000); // 10 seconds timeout

        try {
            const response = await fetch(getEditionUrl(editionToFetch), { signal: controller.signal });
            clearTimeout(timeoutId);
            if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
            const apiData = await response.json();
            const surahs = processApiData(apiData);
            setAllQuranData(prev => ({ ...prev, [editionIdentifier]: surahs }));
        } catch (err) {
            console.warn(`Fetch for ${editionIdentifier} failed or timed out:`, err);
            setError("حدث تأخير في جلب البيانات، سنحاول العمل بما هو متاح.");
        } finally {
            setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
        }
    }, [availableEditions, getEditionUrl, allQuranData, loadingEditions]);

    useEffect(() => {
        const initializeApp = async () => {
            setIsBackgroundLoading(true);
            try {
                // نستخدم Promise.race لضمان عدم توقف التطبيق لأكثر من 12 ثانية عند التحميل الأولي
                await Promise.all([
                    fetchCustomEditionData('quran-simple-clean'),
                    fetchCustomEditionData('quran-uthmani-quran-academy')
                ]);
            } finally {
                setIsInitialLoading(false);
                setIsBackgroundLoading(false);
            }
        };
        initializeApp();
    }, []);

    return {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions, error,
        dataSourceStatus: 'primary' as const, availableEditions,
        fetchCustomEditionData, getEditionUrl,
    };
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import type { Ayah, SavedItem } from './types';
import { useQuranData } from './hooks/useQuranData';
import { useSettings } from './hooks/useSettings';
import { useRouting } from './hooks/useRouting';
import { useAudioPlayer } from './hooks/useAudioPlayer';
import { useNotebook } from './hooks/useNotebook';
import { AuthProvider } from './hooks/useAuth';
import { useSearch } from './hooks/useSearch';
import { useServiceWorkerUpdater } from './hooks/useServiceWorkerUpdater';
import AppRouter from './components/AppRouter';
import TopProgressBar from './components/TopProgressBar';
import SidePanel from './components/SidePanel';
import AudioPlayerBar from './components/AudioPlayerBar';
import Toolbox from './components/Toolbox';
import SaveItemModal from './components/SaveItemModal';
import UpdateNotification from './components/UpdateNotification';
import EditionChoiceModal from './components/EditionChoiceModal';
import { ArrowUpIcon } from './components/icons';
import Header from './components/Header';

const KHATMIYAH_AUDIO_PROGRESS_KEY = 'qran_khatmiyah_audio_progress';
const INITIAL_CHOICE_MADE_KEY = 'qran_initial_choice_made';

const App: React.FC = () => {
    const {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions,
        fetchCustomEditionData, dataSourceStatus
    } = useQuranData();

    const { currentPath, pathParts, queryParams } = useRouting();
    const {
        fontSize, setFontSize, fontStyle, setFontStyle,
        browsingMode, setBrowsingMode, activeEditions, selectedEdition,
        setSelectedEdition, selectedAudioEdition, setSelectedAudioEdition, displayEdition
    } = useSettings();

    const { simpleSearchableAyahs, tryParseAyahReference, performSearch, performSearchByAyahNumber } = useSearch(allQuranData);
    const { playbackInfo, currentlyPlayingAyahGlobalNumber, selectedAudioEditionDetails, handleStartPlayback, handlePlayPause, handleNext, handlePrev, handleClosePlayback, ALL_AUDIO_EDITIONS } = useAudioPlayer(currentPath, allQuranData, selectedAudioEdition, setSelectedAudioEdition, fetchCustomEditionData);
    const { collections, itemToSave, setItemToSave, handleSaveItem, handleConfirmSave, handleDeleteCollection, handleDeleteSavedItem, handleExportNotebook, handleImportNotebook, updateItemNotes } = useNotebook();
    const { showUpdateNotification, handleUpdate } = useServiceWorkerUpdater();

    const [isSearching, setIsSearching] = useState<boolean>(false);
    const [showScroll, setShowScroll] = useState(false);
    const [isSidePanelOpen, setIsSidePanelOpen] = useState(false);
    const [showEditionChoice, setShowEditionChoice] = useState(false);

    const [audioKhatmiyahProgress, setAudioKhatmiyahProgress] = useState<{ ayahNumber: number } | null>(() => {
        try {
            const stored = localStorage.getItem(KHATMIYAH_AUDIO_PROGRESS_KEY);
            if (stored) return JSON.parse(stored);
        } catch (e) {}
        return { ayahNumber: 1 };
    });

    useEffect(() => {
        if (!localStorage.getItem(INITIAL_CHOICE_MADE_KEY)) setShowEditionChoice(true);
    }, []);

    const handleInitialChoice = (editionIdentifier: string, dontShowAgain: boolean) => {
        if (editionIdentifier === 'quran-uthmani-quran-academy') {
            setFontStyle('uthmani'); setSelectedEdition('quran-uthmani-quran-academy'); setBrowsingMode('page');
        } else {
            setFontStyle('imlai_1'); setSelectedEdition('quran-simple-clean'); setBrowsingMode('full');
        }
        if (dontShowAgain) localStorage.setItem(INITIAL_CHOICE_MADE_KEY, 'true');
        setShowEditionChoice(false);
    };

    useEffect(() => {
        const checkScrollTop = () => setShowScroll(window.pageYOffset > 400);
        window.addEventListener('scroll', checkScrollTop);
        return () => window.removeEventListener('scroll', checkScrollTop);
    }, []);

    useEffect(() => {
        if (!isInitialLoading) {
            const loader = document.querySelector('.static-loader');
            if (loader) {
                (loader as HTMLElement).style.opacity = '0';
                setTimeout(() => loader.remove(), 400);
            }
        }
    }, [isInitialLoading]);

