import { useState, useEffect, useCallback } from 'react';
import type { SurahData, QuranEdition } from '../types';

const CORE_EDITIONS: QuranEdition[] = [
    { identifier: "quran-simple-clean", language: "ar", name: "المصحف المبسط", englishName: "Simple Clean", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" },
    { identifier: "quran-uthmani-quran-academy", language: "ar", name: "الرسم العثماني", englishName: "Uthmani (Quran Academy)", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" }
];

export const useQuranData = () => {
    const [allQuranData, setAllQuranData] = useState<{ [key: string]: SurahData[] } | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isBackgroundLoading, setIsBackgroundLoading] = useState(false);
    const [loadingEditions, setLoadingEditions] = useState<string[]>([]);
    const [error, setError] = useState<string | null>(null);
    const [availableEditions] = useState<QuranEdition[]>(CORE_EDITIONS);

    const getEditionUrl = (edition: QuranEdition): string => {
        if (edition.identifier === 'quran-simple-clean') return 'https://api.alquran.cloud/v1/quran/quran-simple-clean';
        return `https://api.alquran.cloud/v1/quran/${edition.identifier}`;
    };

    const fetchEdition = async (id: string): Promise<SurahData[] | null> => {
        const edition = availableEditions.find(e => e.identifier === id);
        if (!edition) return null;

        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 6000); // 6s fast timeout

        try {
            const response = await fetch(getEditionUrl(edition), { signal: controller.signal });
            clearTimeout(timeoutId);
            if (!response.ok) throw new Error("Network response was not ok");
            const result = await response.json();
            return result.data?.surahs || null;
        } catch (err) {
            console.warn(`Failed to fetch edition ${id}:`, err);
            return null;
        }
    };

    const fetchCustomEditionData = useCallback(async (editionIdentifier: string) => {
        if (allQuranData?.[editionIdentifier] || loadingEditions.includes(editionIdentifier)) return;
        setLoadingEditions(prev => [...prev, editionIdentifier]);
        const data = await fetchEdition(editionIdentifier);
        if (data) setAllQuranData(prev => ({ ...prev, [editionIdentifier]: data }));
        setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
    }, [allQuranData, loadingEditions, availableEditions]);

    useEffect(() => {
        const initialize = async () => {
            setIsBackgroundLoading(true);
            const [simple, uthmani] = await Promise.all([
                fetchEdition('quran-simple-clean'),
                fetchEdition('quran-uthmani-quran-academy')
            ]);

            const newData: { [key: string]: SurahData[] } = {};
            if (simple) newData['quran-simple-clean'] = simple;
            if (uthmani) newData['quran-uthmani-quran-academy'] = uthmani;

            if (Object.keys(newData).length > 0) {
                setAllQuranData(newData);
            } else {
                setError("فشل تحميل البيانات الأساسية. يرجى التحقق من اتصالك.");
            }

            setIsInitialLoading(false);
            setIsBackgroundLoading(false);
        };
        initialize();
    }, []);

    return {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions, error,
        dataSourceStatus: error ? 'fallback' : 'primary' as const, availableEditions,
        fetchCustomEditionData
    };
};

import { useState, useEffect, useCallback } from 'react';
import type { SurahData, QuranEdition } from '../types';

const CORE_EDITIONS: QuranEdition[] = [
    { identifier: "quran-simple-clean", language: "ar", name: "المصحف المبسط", englishName: "Simple Clean", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" },
    { identifier: "quran-uthmani-quran-academy", language: "ar", name: "الرسم العثماني", englishName: "Uthmani (Quran Academy)", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" }
];

export const useQuranData = () => {
    const [allQuranData, setAllQuranData] = useState<{ [key: string]: SurahData[] } | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isBackgroundLoading, setIsBackgroundLoading] = useState(false);
    const [loadingEditions, setLoadingEditions] = useState<string[]>([]);
    const [error, setError] = useState<string | null>(null);
    const [availableEditions] = useState<QuranEdition[]>(CORE_EDITIONS);

    const fetchWithTimeout = async (url: string, timeout = 4000) => {
        const controller = new AbortController();
        const id = setTimeout(() => controller.abort(), timeout);
        try {
            const response = await fetch(url, { signal: controller.signal });
            clearTimeout(id);
            return response;
        } catch (e) {
            clearTimeout(id);
            throw e;
        }
    };

    const fetchEdition = async (id: string): Promise<SurahData[] | null> => {
        const edition = availableEditions.find(e => e.identifier === id);
        if (!edition) return null;

        const url = id === 'quran-simple-clean' 
            ? 'https://api.alquran.cloud/v1/quran/quran-simple-clean'
            : `https://api.alquran.cloud/v1/quran/${id}`;

        try {
            const response = await fetchWithTimeout(url);
            if (!response.ok) return null;
            const result = await response.json();
            return result.data?.surahs || null;
        } catch (err) {
            console.warn(`Failed to fetch ${id}:`, err);
            return null;
        }
    };

    const fetchCustomEditionData = useCallback(async (editionIdentifier: string) => {
        if (allQuranData?.[editionIdentifier] || loadingEditions.includes(editionIdentifier)) return;
        setLoadingEditions(prev => [...prev, editionIdentifier]);
        const data = await fetchEdition(editionIdentifier);
        if (data) setAllQuranData(prev => ({ ...prev, [editionIdentifier]: data }));
        setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
    }, [allQuranData, loadingEditions]);

    useEffect(() => {
        const initialize = async () => {
            setIsBackgroundLoading(true);
            try {
                // نحاول جلب النسخة المبسطة أولاً لأنها الأخف والأهم للبحث
                const simple = await fetchEdition('quran-simple-clean');

                if (simple) {
                    setAllQuranData({ 'quran-simple-clean': simple });
                    // جلب النسخة العثمانية في الخلفية
                    fetchEdition('quran-uthmani-quran-academy').then(uthmani => {
                        if (uthmani) {
                            setAllQuranData(prev => ({ ...prev!, 'quran-uthmani-quran-academy': uthmani }));
                        }
                    });
                } else {
                    setError("فشل الاتصال بخادم البيانات. يرجى المحاولة لاحقاً.");
                }
            } finally {
                setIsInitialLoading(false);
                setIsBackgroundLoading(false);
            }
        };
        initialize();
    }, []);

    return {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions, error,
        dataSourceStatus: error ? 'fallback' : 'primary' as const, availableEditions,
        fetchCustomEditionData
    };
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import type { Ayah, SavedItem } from './types';
import { useQuranData } from './hooks/useQuranData';
import { useSettings } from './hooks/useSettings';
import { useRouting } from './hooks/useRouting';
