const App: React.FC = () => {
    const {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions,
        fetchCustomEditionData, dataSourceStatus, error: dataError
    } = useQuranData();

    const { currentPath, pathParts, queryParams } = useRouting();
    const {
        fontSize, setFontSize, fontStyle, setFontStyle,
        browsingMode, setBrowsingMode, activeEditions, selectedEdition,
        setSelectedEdition, selectedAudioEdition, setSelectedAudioEdition, displayEdition
    } = useSettings();

    const { simpleSearchableAyahs, tryParseAyahReference, performSearch, performSearchByAyahNumber } = useSearch(allQuranData);
    const { playbackInfo, currentlyPlayingAyahGlobalNumber, selectedAudioEditionDetails, handleStartPlayback, handlePlayPause, handleNext, handlePrev, handleClosePlayback, ALL_AUDIO_EDITIONS } = useAudioPlayer(currentPath, allQuranData, selectedAudioEdition, setSelectedAudioEdition, fetchCustomEditionData);
    const { collections, itemToSave, setItemToSave, handleSaveItem, handleConfirmSave, handleDeleteCollection, handleDeleteSavedItem, handleExportNotebook, handleImportNotebook, updateItemNotes } = useNotebook();
    const { showUpdateNotification, handleUpdate } = useServiceWorkerUpdater();

    const [isSearching, setIsSearching] = useState<boolean>(false);
    const [showScroll, setShowScroll] = useState(false);
    const [isSidePanelOpen, setIsSidePanelOpen] = useState(false);
    const [showEditionChoice, setShowEditionChoice] = useState(false);

    const [audioKhatmiyahProgress, setAudioKhatmiyahProgress] = useState<{ ayahNumber: number } | null>(() => {
        try {
            const stored = localStorage.getItem(KHATMIYAH_AUDIO_PROGRESS_KEY);
            if (stored) return JSON.parse(stored);
        } catch (e) {}
        return { ayahNumber: 1 };
    });

    useEffect(() => {
        if (!localStorage.getItem(INITIAL_CHOICE_MADE_KEY)) {
            setShowEditionChoice(true);
        }
    }, []);

    // Force hide loader when initial loading finishes
    useEffect(() => {
        if (!isInitialLoading) {
            const loader = document.querySelector('.static-loader');
            if (loader) {
                (loader as HTMLElement).style.opacity = '0';
                setTimeout(() => loader.remove(), 500);
            }
        }
    }, [isInitialLoading]);

    useEffect(() => {
        const checkScrollTop = () => setShowScroll(window.pageYOffset > 400);
        window.addEventListener('scroll', checkScrollTop);
        return () => window.removeEventListener('scroll', checkScrollTop);
    }, []);

    const handleSearch = (query: string, sourceEdition?: string, position?: { surah: number; ayah: number; wordIndex: number; }) => {
        const ayahRef = tryParseAyahReference(query);
        if (ayahRef && !position) { window.location.hash = `#/surah/${ayahRef.surah}?ayah=${ayahRef.ayah}`; return; }
        setIsSearching(true);
        let url = `#/search/${encodeURIComponent(query)}?search_edition=${sourceEdition || 'quran-simple-clean'}`;
        if (position) url += `&s=${position.surah}&a=${position.ayah}&w=${position.wordIndex}`;
        window.location.hash = url;
    };

    const quranData = useMemo(() => allQuranData?.[selectedEdition], [allQuranData, selectedEdition]);
    const hizbQuarterStartMap = useMemo(() => {
        const map = new Map<number, number>();
        simpleSearchableAyahs.forEach(ayah => { if (ayah.hizbQuarter && !map.has(ayah.hizbQuarter)) map.set(ayah.hizbQuarter, ayah.number); });
        return map;
    }, [simpleSearchableAyahs]);

    const isAudioKhatmiyahPage = currentPath.startsWith('#/audio-khatmiyah');
    const isPageWithToolbox = useMemo(() => (currentPath.startsWith('#/surah/') || currentPath.startsWith('#/search/') || currentPath.startsWith('#/page/')) && !isAudioKhatmiyahPage, [currentPath, isAudioKhatmiyahPage]);

    return (
        <AuthProvider>
            <div className="bg-background text-text-primary min-h-screen transition-colors duration-300">
                {showEditionChoice && <EditionChoiceModal onSelect={(id, skip) => {
                    if (id === 'quran-uthmani-quran-academy') { setFontStyle('uthmani'); setSelectedEdition('quran-uthmani-quran-academy'); setBrowsingMode('page'); }
                    else { setFontStyle('imlai_1'); setSelectedEdition('quran-simple-clean'); setBrowsingMode('full'); }
                    if (skip) localStorage.setItem(INITIAL_CHOICE_MADE_KEY, 'true');
                    setShowEditionChoice(false);
                }} />}

                <TopProgressBar isSearching={isSearching || isBackgroundLoading || loadingEditions.length > 0} />
                <SidePanel isOpen={isSidePanelOpen} onClose={() => setIsSidePanelOpen(false)} currentPath={currentPath} onNavigate={(path) => { window.location.hash = path; setIsSidePanelOpen(false); }} />

                {dataError && (
                    <div className="fixed top-20 left-4 right-4 z-50 bg-red-500 text-white p-3 rounded-lg shadow-lg text-center">
                        {dataError}
                    </div>
                )}

                {!isAudioKhatmiyahPage && (
                    <Header setIsSidePanelOpen={setIsSidePanelOpen} currentPath={currentPath} dataSourceStatus={dataSourceStatus as 'primary' | 'fallback'} onSearch={handleSearch} searchDisabled={isInitialLoading} selectedEdition={selectedEdition} setSelectedEdition={setSelectedEdition} fontStyle={fontStyle} setFontStyle={setFontStyle} browsingMode={browsingMode} setBrowsingMode={setBrowsingMode} loadingEditions={loadingEditions} onStartPlayback={handleStartPlayback} isPlaybackLoading={!!playbackInfo?.trigger} selectedAudioEdition={selectedAudioEdition} />
                )}

                <main className={`pt-8 pb-24 ${isAudioKhatmiyahPage ? 'pt-0' : ''}`}>
                    <AppRouter pathParts={pathParts} queryParams={queryParams} isInitialLoading={isInitialLoading} quranData={quranData} simpleSearchableAyahs={simpleSearchableAyahs} collections={collections} audioKhatmiyahProgress={audioKhatmiyahProgress} handleSaveAudioKhatmiyahProgress={(n) => { setAudioKhatmiyahProgress({ayahNumber: n}); localStorage.setItem(KHATMIYAH_AUDIO_PROGRESS_KEY, JSON.stringify({ayahNumber: n})); }} ALL_AUDIO_EDITIONS={ALL_AUDIO_EDITIONS} selectedAudioEdition={selectedAudioEdition} setSelectedAudioEdition={setSelectedAudioEdition} allQuranData={allQuranData} fetchCustomEditionData={fetchCustomEditionData} fontSize={fontSize} setFontSize={setFontSize} fontStyle={fontStyle} activeEditions={activeEditions} selectedEdition={selectedEdition} setSelectedEdition={setSelectedEdition} handleDeleteCollection={handleDeleteCollection} handleDeleteSavedItem={handleDeleteSavedItem} updateItemNotes={updateItemNotes} handleExportNotebook={handleExportNotebook} handleImportNotebook={handleImportNotebook} handleSearch={handleSearch} displayEdition={displayEdition} browsingMode={browsingMode} handleSaveItem={handleSaveItem as (item: SavedItem) => void} handleSearchByAyahNumber={(n) => { setIsSearching(true); window.location.hash = `#/search/number/${n}`; }} currentlyPlayingAyahGlobalNumber={currentlyPlayingAyahGlobalNumber} playbackInfo={playbackInfo} handleStartPlayback={handleStartPlayback as (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void} hizbQuarterStartMap={hizbQuarterStartMap} setIsSearching={setIsSearching} performSearchByAyahNumber={performSearchByAyahNumber} performSearch={performSearch} />
                </main>

                {isPageWithToolbox && <Toolbox fontSize={fontSize} onFontSizeChange={setFontSize} isAudioPlayerVisible={!!playbackInfo} browsingMode={browsingMode} onBrowsingModeChange={setBrowsingMode} />}
                {itemToSave && <SaveItemModal item={itemToSave} collections={collections} onClose={() => setItemToSave(null)} onSave={handleConfirmSave} />}
                {playbackInfo && !isAudioKhatmiyahPage && <AudioPlayerBar playlist={playbackInfo.playlist} currentIndex={playbackInfo.currentIndex} isPlaying={playbackInfo.isPlaying} isLoading={!!playbackInfo?.trigger} onPlayPause={handlePlayPause} onNext={handleNext} onPrev={handlePrev} onEnded={handleNext} onClose={handleClosePlayback} audioEdition={selectedAudioEditionDetails} />}
                {showScroll && !isAudioKhatmiyahPage && <button onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })} className={`fixed left-8 p-4 bg-primary text-white rounded-full shadow-lg hover:bg-primary-hover transition-all duration-300 ${!!playbackInfo ? 'bottom-28' : 'bottom-8'}`}><ArrowUpIcon className="w-6 h-6" /></button>}
                {showUpdateNotification && <UpdateNotification onUpdate={handleUpdate} />}
            </div>
        </AuthProvider>
    );
};

export default App;
